export function readDataBase(data) {
    let openReq = indexedDB.open("Post_User_DB", 1)
    let db;
    let transaction;

    openReq.onupgradeneeded = function (e) {
        db = e.target.result;
        if (!db.objectStoreNames.contains("user-post-1")) {
            db.createObjectStore("user-post-1")
        }
    }

    openReq.onsuccess = function (e) {
        console.log("Success!");
        db = e.target.result;

        transaction = db.transaction(["user-post-1"],"readonly");
        const store = transaction.objectStore("user-post-1");

        store.openCursor().onsuccess = e => {
            const result = e.target.result;
            if (result) {
              console.log("Key", result.key)
              console.log("Data", result.value)
              result.continue()
            }
          }
    }
    openReq.onerror = function (e) {
        console.log("Error");
        console.dir(e);
    }
}
